/// Identity matrix of dimension n.
fn identity(n: usize) -> Vec<Vec<Q>> {
    let mut m = vec![vec![Q::zero(); n]; n];
    for i in 0..n { m[i][i] = Q::one(); }
    m
}

/// Matrix multiplication A × B over Q.
#[cfg(test)]
fn mat_mul(a: &[Vec<Q>], b: &[Vec<Q>], n: usize) -> Vec<Vec<Q>> {
    let mut c = vec![vec![Q::zero(); n]; n];
    for i in 0..n {
        for j in 0..n {
            for k in 0..n {
                c[i][j] = &c[i][j] + &(&a[i][k] * &b[k][j]);
            }
        }
    }
    c
}

