    let one_minus_s2 = Q::one() - &s2;

    let mat = vec![
        vec![&one_minus_s2 * &denom_inv, &(-&two_s) * &denom_inv, Q::zero()],
        vec![&two_s * &denom_inv, &one_minus_s2 * &denom_inv, Q::zero()],
        vec![Q::zero(), Q::zero(), Q::one()],
    ];
    // A⁻¹ = (I + S)(I - S)⁻¹ — same formula with s → -s
