/// General matrix multiplication A × B over Q for n×n matrices.
fn mat_mul_general(a: &[Vec<Q>], b: &[Vec<Q>], n: usize) -> Vec<Vec<Q>> {
    let mut c = vec![vec![Q::zero(); n]; n];
    for i in 0..n {
        for j in 0..n {
            for k in 0..n {
                c[i][j] = &c[i][j] + &(&a[i][k] * &b[k][j]);
            }
        }
    }
    c
}

/// Invert an n×n rational matrix via Gauss-Jordan elimination.
/// Returns None if the matrix is singular (should not happen for I + ε·S
/// with antisymmetric S, but we check rather than assume).
fn invert_rational_matrix(mat: &[Vec<Q>], n: usize) -> Option<Vec<Vec<Q>>> {
    // Augment [mat | I]
    let mut aug: Vec<Vec<Q>> = (0..n).map(|i| {
        let mut row = mat[i].clone();
        row.extend((0..n).map(|j| if i == j { Q::one() } else { Q::zero() }));
        row
    }).collect();

    // Forward elimination with partial pivoting
    for col in 0..n {
        // Find pivot
        let pivot_row = (col..n).find(|&r| !aug[r][col].is_zero())?;
        aug.swap(col, pivot_row);

        // Scale pivot row
        let pivot = aug[col][col].clone();
        for j in 0..(2 * n) {
            aug[col][j] = &aug[col][j] / &pivot;
        }

        // Eliminate column in all other rows
        for i in 0..n {
            if i == col { continue; }
            let factor = aug[i][col].clone();
            for j in 0..(2 * n) {
                let sub = &factor * &aug[col][j];
                aug[i][j] = &aug[i][j] - &sub;
            }
        }
    }

    // Extract inverse from right half
    Some(aug.into_iter().map(|row| row[n..].to_vec()).collect())
}

